    51â†’// GenerateContent converts the ADK request to an OpenAI chat completion request,
    52â†’// calls the API, and converts the response back to an LLMResponse.
    53â†’// Streaming is not implemented; the iterator always yields a single response.
    54â†’func (m *openaiModel) GenerateContent(ctx context.Context, req *model.LLMRequest, _ bool) iter.Seq2[*model.LLMResponse, error] {
    55â†’	return func(yield func(*model.LLMResponse, error) bool) {
    56â†’		resp, err := m.doRequest(ctx, req)
    57â†’		if err != nil {
    58â†’			yield(nil, err)
    59â†’			return
    60â†’		}
    61â†’		yield(resp, nil)
    62â†’	}
    63â†’}
