   197â†’// convertContents transforms ADK genai.Content messages into OpenAI chat messages.
   198â†’func convertContents(req *model.LLMRequest) []chatMessage {
   199â†’	var msgs []chatMessage
   200â†’
   201â†’	// System instruction.
   202â†’	if req.Config != nil && req.Config.SystemInstruction != nil {
   203â†’		var text string
   204â†’		for _, p := range req.Config.SystemInstruction.Parts {
   205â†’			if p.Text != "" {
   206â†’				text += p.Text
   207â†’			}
   208â†’		}
   209â†’		if text != "" {
   210â†’			msgs = append(msgs, chatMessage{Role: "system", Content: text})
   211â†’		}
   212â†’	}
   213â†’
   214â†’	// Conversation contents.
   215â†’	for _, c := range req.Contents {
   216â†’		role := mapRole(c.Role)
   217â†’
   218â†’		// Check each part: could be text, function_call, or function_response.
   219â†’		for _, p := range c.Parts {
   220â†’			switch {
   221â†’			case p.FunctionCall != nil:
   222â†’				argsJSON, _ := json.Marshal(p.FunctionCall.Args)
   223â†’				msgs = append(msgs, chatMessage{
   224â†’					Role: "assistant",
   225â†’					ToolCalls: []toolCall{{
   226â†’						ID:   p.FunctionCall.ID,
   227â†’						Type: "function",
   228â†’						Function: functionCall{
   229â†’							Name:      p.FunctionCall.Name,
   230â†’							Arguments: string(argsJSON),
   231â†’						},
   232â†’					}},
   233â†’				})
   234â†’			case p.FunctionResponse != nil:
   235â†’				respJSON, _ := json.Marshal(p.FunctionResponse.Response)
   236â†’				msgs = append(msgs, chatMessage{
   237â†’					Role:       "tool",
   238â†’					Content:    string(respJSON),
   239â†’					ToolCallID: p.FunctionResponse.ID,
   240â†’				})
   241â†’			case p.Text != "":
   242â†’				msgs = append(msgs, chatMessage{Role: role, Content: p.Text})
   243â†’			}
   244â†’		}
   245â†’	}
   246â†’
   247â†’	// Merge consecutive assistant messages with tool_calls.
   248â†’	msgs = mergeAssistantToolCalls(msgs)
   249â†’
   250â†’	return msgs
   251â†’}
   252â†’
   253â†’// mergeAssistantToolCalls combines adjacent assistant messages that each have
   254â†’// tool_calls into a single message, as OpenAI expects multiple tool_calls in
   255â†’// one message rather than separate messages.
   256â†’func mergeAssistantToolCalls(msgs []chatMessage) []chatMessage {
   257â†’	if len(msgs) == 0 {
   258â†’		return msgs
   259â†’	}
   260â†’	var merged []chatMessage
   261â†’	for _, msg := range msgs {
   262â†’		if msg.Role == "assistant" && len(msg.ToolCalls) > 0 && len(merged) > 0 {
   263â†’			prev := &merged[len(merged)-1]
   264â†’			if prev.Role == "assistant" && len(prev.ToolCalls) > 0 {
   265â†’				prev.ToolCalls = append(prev.ToolCalls, msg.ToolCalls...)
   266â†’				continue
   267â†’			}
   268â†’		}
   269â†’		merged = append(merged, msg)
   270â†’	}
   271â†’	return merged
   272â†’}
