   274â†’// convertTools transforms ADK genai.Tool definitions into OpenAI tool format.
   275â†’func convertTools(req *model.LLMRequest) []chatTool {
   276â†’	if req.Config == nil || len(req.Config.Tools) == 0 {
   277â†’		return nil
   278â†’	}
   279â†’
   280â†’	var tools []chatTool
   281â†’	for _, t := range req.Config.Tools {
   282â†’		for _, fd := range t.FunctionDeclarations {
   283â†’			ct := chatTool{
   284â†’				Type: "function",
   285â†’				Function: chatFunction{
   286â†’					Name:        fd.Name,
   287â†’					Description: fd.Description,
   288â†’				},
   289â†’			}
   290â†’			if fd.Parameters != nil {
   291â†’				ct.Function.Parameters = schemaToMap(fd.Parameters)
   292â†’			}
   293â†’			tools = append(tools, ct)
   294â†’		}
   295â†’	}
   296â†’	return tools
   297â†’}
