   299â†’// schemaToMap converts a genai.Schema to a JSON-serialisable map that matches
   300â†’// the OpenAI function parameters format (JSON Schema).
   301â†’func schemaToMap(s *genai.Schema) map[string]any {
   302â†’	m := map[string]any{}
   303â†’	if s.Type != "" {
   304â†’		m["type"] = string(s.Type)
   305â†’	}
   306â†’	if s.Description != "" {
   307â†’		m["description"] = s.Description
   308â†’	}
   309â†’	if len(s.Enum) > 0 {
   310â†’		m["enum"] = s.Enum
   311â†’	}
   312â†’	if s.Items != nil {
   313â†’		m["items"] = schemaToMap(s.Items)
   314â†’	}
   315â†’	if len(s.Properties) > 0 {
   316â†’		props := map[string]any{}
   317â†’		for k, v := range s.Properties {
   318â†’			props[k] = schemaToMap(v)
   319â†’		}
   320â†’		m["properties"] = props
   321â†’	}
   322â†’	if len(s.Required) > 0 {
   323â†’		m["required"] = s.Required
   324â†’	}
   325â†’	return m
   326â†’}
