   328â†’// convertResponse transforms an OpenAI chat completion response into an ADK LLMResponse.
   329â†’func convertResponse(resp *chatResponse) *model.LLMResponse {
   330â†’	llmResp := &model.LLMResponse{
   331â†’		TurnComplete: true,
   332â†’	}
   333â†’
   334â†’	if len(resp.Choices) == 0 {
   335â†’		llmResp.Content = genai.NewContentFromText("", "model")
   336â†’		return llmResp
   337â†’	}
   338â†’
   339â†’	choice := resp.Choices[0]
   340â†’	llmResp.FinishReason = mapFinishReason(choice.FinishReason)
   341â†’
   342â†’	content := &genai.Content{Role: "model"}
   343â†’
   344â†’	// Text content.
   345â†’	if choice.Message.Content != "" {
   346â†’		content.Parts = append(content.Parts, &genai.Part{Text: choice.Message.Content})
   347â†’	}
   348â†’
   349â†’	// Tool calls.
   350â†’	for _, tc := range choice.Message.ToolCalls {
   351â†’		var args map[string]any
   352â†’		if tc.Function.Arguments != "" {
   353â†’			_ = json.Unmarshal([]byte(tc.Function.Arguments), &args)
   354â†’		}
   355â†’		content.Parts = append(content.Parts, &genai.Part{
   356â†’			FunctionCall: &genai.FunctionCall{
   357â†’				ID:   tc.ID,
   358â†’				Name: tc.Function.Name,
   359â†’				Args: args,
   360â†’			},
   361â†’		})
   362â†’	}
   363â†’
   364â†’	llmResp.Content = content
   365â†’
   366â†’	if resp.Usage != nil {
   367â†’		llmResp.UsageMetadata = &genai.GenerateContentResponseUsageMetadata{
   368â†’			PromptTokenCount:     resp.Usage.PromptTokens,
   369â†’			CandidatesTokenCount: resp.Usage.CompletionTokens,
   370â†’			TotalTokenCount:      resp.Usage.TotalTokens,
   371â†’		}
   372â†’	}
   373â†’
   374â†’	return llmResp
   375â†’}
