   377â†’func mapRole(role string) string {
   378â†’	switch role {
   379â†’	case "model":
   380â†’		return "assistant"
   381â†’	default:
   382â†’		return role
   383â†’	}
   384â†’}
   385â†’
   386â†’func mapFinishReason(reason string) genai.FinishReason {
   387â†’	switch reason {
   388â†’	case "stop":
   389â†’		return genai.FinishReasonStop
   390â†’	case "length":
   391â†’		return genai.FinishReasonMaxTokens
   392â†’	case "tool_calls":
   393â†’		return genai.FinishReasonStop
   394â†’	case "content_filter":
   395â†’		return genai.FinishReasonSafety
   396â†’	default:
   397â†’		return genai.FinishReasonOther
   398â†’	}
